using System.Linq; using System.Data.Entity; using System.Windows; using System.Windows.Controls; using EpsteinMarket.ApplicationData;
namespace EpsteinMarket.Pages { public partial class StockItemDetailsPage:Page { Products product; public StockItemDetailsPage(Products p){InitializeComponent(); product=AppConnect.model01.Products.Include("Categories").Include("Suppliers").Include("Units").Include("StockBalances.StorageLocations").First(x=>x.ProductID==p.ProductID); tbName.Text=product.ProductName; tbPrice.Text="Цена: "+product.SalePrice+" ₽"; tbCategory.Text="Категория: "+product.Categories.CategoryName; tbBrand.Text="Поставщик: "+product.Suppliers.SupplierName; tbStatus.Text="Ед. изм.: "+product.Units.ShortName; tbQuantity.Text="Остаток: "+product.QuantityInStock; tbDescription.Text=product.Description;} private void btnBack_Click(object s,RoutedEventArgs e){AppFrame.frmMain.GoBack();} private void btnAddToCart_Click(object s,RoutedEventArgs e){MessageBox.Show("Используйте отгрузки для списания товара со склада");} private void btnThumbnail_Click(object s,RoutedEventArgs e){} }}
